#include <iostream>
#include <fstream>

int main() {
    std::ofstream file("output.txt");
    if (file.is_open()) {
        file << "Hello, file!" << std::endl;
        file << "Second line" << std::endl;
        file.close();
        std::cout << "Запись выполнена" << std::endl;
    } else {
        std::cout << "Не удалось открыть файл" << std::endl;
    }
    return 0;
}

